// src/index.js

import React from "react";
import ReactDOM from "react-dom/client";
import App from "./App"; // Make sure the path to App.js is correct
import { AuthProvider } from "./context/AuthContext"; // Import your AuthContext
import { BrowserRouter } from "react-router-dom"; // Import BrowserRouter

// Create a root element for React
const root = ReactDOM.createRoot(document.getElementById("root"));

// Render the application
root.render(
  <React.StrictMode>
    <BrowserRouter> {/* Provide routing context */}
      <AuthProvider> {/* Provide authentication context */}
        <App /> {/* Render your main application */}
      </AuthProvider>
    </BrowserRouter>
  </React.StrictMode>
);
